import{_ as a,o as e,c as r,a9 as o}from"./chunks/framework.D4xYp1Zt.js";const s="/images/100-blocks-day/100-blocks-a-day.png",l="/images/100-blocks-day/1-block.jpg",n="/images/100-blocks-day/100-blocks.png",p="/images/100-blocks-day/Desk.png",c="/images/100-blocks-day/pinit_fg_en_rect_gray_20.png",f=JSON.parse('{"title":"100 Blocks a Day","description":"","frontmatter":{"title":"100 Blocks a Day","titleZh":"每天100个方块","date":"2016-10-22T00:00:00.000Z","originalUrl":"https://waitbutwhy.com/2016/10/100-blocks-day.html","slug":"100-blocks-day"},"headers":[],"relativePath":"posts/100-blocks-day.md","filePath":"posts/100-blocks-day.md","lastUpdated":1782886257000}'),i={name:"posts/100-blocks-day.md"};function h(b,t,k,d,m,g){return e(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="每天100个方块-·-100-blocks-a-day" tabindex="-1">每天100个方块 · 100 Blocks a Day <a class="header-anchor" href="#每天100个方块-·-100-blocks-a-day" aria-label="Permalink to &quot;每天100个方块 · 100 Blocks a Day&quot;">​</a></h1><blockquote><p>原文:<a href="https://waitbutwhy.com/2016/10/100-blocks-day.html" target="_blank" rel="noreferrer">https://waitbutwhy.com/2016/10/100-blocks-day.html</a> · 2016-10-22</p></blockquote><p>大多数人每晚睡大约七到八个小时。这意味着每天有 16 或 17 个小时是醒着的。差不多 1000 分钟。</p><p>我们把这 1000 分钟想象成 100 个 10 分钟的小方块。这就是你每天醒来时手里握着的东西。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/10/100-blocks-a-day.png" target="_blank" rel="noreferrer"><img src="'+s+'" alt="100-blocks-a-day"></a></p><p>一天下来,你在每个方块上花掉 10 分钟的生命,直到方块最终用完,该睡觉了。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/10/1-block.jpg" target="_blank" rel="noreferrer"><img src="'+l+'" alt="1-block"></a></p><p>时不时退一步想想我们每天是怎么使用这 100 个方块的,总是件好事。有多少方块用来让你的未来更好?有多少纯粹只是拿来享受的?有多少花在了别人身上,有多少留给了自己?有多少用来创造,有多少用来消费?有多少专注在身体上,有多少在头脑上,又有多少哪个都不算?一天中你最喜欢哪些方块,最不喜欢哪些?</p><p>想象这些方块排列成一个网格。如果你必须给每一个都贴上用途的标签,会怎样?</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/10/100-blocks-pdf.pdf" target="_blank" rel="noreferrer"><img src="'+n+'" alt="100-blocks"></a></p><p>你就得开始思考:每一件你可能花时间做的事,值几个方块?做晚饭要花 3 个方块,叫外卖只花 0 个——做晚饭对你来说值那 3 个方块吗?每天 10 分钟的冥想,重要到值得为它专门留一个方块吗?每晚读 20 分钟书,一年就能多读 15 本书——这值 2 个方块吗?如果你最喜欢的娱乐是玩电子游戏,那你得先想清楚自己有多看重&quot;乐趣&quot;这件事,再决定它值几个方块。下班后跟朋友喝一杯大概要占 10 个方块。这种事你愿意多久花 10 个方块一次?又是花在哪些朋友身上?哪些方块的用途应该是雷打不动的,哪些可以灵活一点?哪些方块应该完全留白,不预设任何用途?</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/10/Desk.png" target="_blank" rel="noreferrer"><img src="'+p+'" alt="desk"></a></p><p>现在再想象一个类似的网格,但这次每个方块上贴的标签,是你昨天实际上把它花在了什么上面。</p><h2 id="要问自己的问题是-这两个网格有什么不一样-为什么" tabindex="-1">要问自己的问题是:这两个网格有什么不一样?为什么? <a class="header-anchor" href="#要问自己的问题是-这两个网格有什么不一样-为什么" aria-label="Permalink to &quot;要问自己的问题是:这两个网格有什么不一样?为什么?&quot;">​</a></h2><h2 id="提示-点击上面的网格可以打印。" tabindex="-1">提示:点击上面的网格可以打印。 <a class="header-anchor" href="#提示-点击上面的网格可以打印。" aria-label="Permalink to &quot;提示:点击上面的网格可以打印。&quot;">​</a></h2><p><strong>趁我们都还在这个状态里:</strong></p><p><strong><a href="https://waitbutwhy.com/2014/05/life-weeks.html" target="_blank" rel="noreferrer">你的一生,画在一张网格上。</a></strong></p><p><strong><a href="https://waitbutwhy.com/2015/12/the-tail-end.html" target="_blank" rel="noreferrer">一个赤裸裸的提醒。</a></strong></p><h2 id="如果你手边有一张打印出来的方格图-那么-这篇文章-或许值得先读一读。" tabindex="-1">如果你手边有一张打印出来的方格图,那么 <strong><a href="https://waitbutwhy.com/2014/10/religion-for-the-nonreligious.html" target="_blank" rel="noreferrer">这篇文章</a></strong> 或许值得先读一读。 <a class="header-anchor" href="#如果你手边有一张打印出来的方格图-那么-这篇文章-或许值得先读一读。" aria-label="Permalink to &quot;如果你手边有一张打印出来的方格图,那么 **[这篇文章](https://waitbutwhy.com/2014/10/religion-for-the-nonreligious.html)** 或许值得先读一读。&quot;">​</a></h2><p>如果你喜欢 Wait But Why,请订阅我们的 <strong><a href="https://newsletter.waitbutwhy.com/join" target="_blank" rel="noreferrer">邮件列表</a></strong>,新文章发布时我们会发送给你。</p><p>想支持 Wait But Why,请访问我们的 <strong><a href="https://patreon.com/waitbutwhy" target="_blank" rel="noreferrer">Patreon 页面</a></strong>。</p><p><a href="https://twitter.com/share" target="_blank" rel="noreferrer">Tweet</a></p><p><a href="//www.pinterest.com/pin/create/button/?url=https://waitbutwhy.com/2016/10/100-blocks-day.html&amp;description=100%20Blocks%20a%20Day" target="_blank" rel="noreferrer"><img src="'+c+'" alt=""></a></p>',23)])])}const u=a(i,[["render",h]]);export{f as __pageData,u as default};
